import { z } from 'zod';
export const TiktokDlArgsSchema = z.object({
    0: z.string().url()
});
export const TiktokDlSchema = z.object({
    nickname: z.string(),
    username: z.string(),
    avatar: z.string().url().optional(),
    description: z.string(),
    thumbnail: z.string().url().optional(),
    played: z.string(),
    commented: z.string(),
    saved: z.string(),
    shared: z.string(),
    song: z.string(),
    video: z.object({
        noWatermark: z.string().url().optional(),
        withWatermark: z.string().url().optional()
    }),
    audio: z.string().url().optional()
});
